var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"어때? 함선 신호 잡혀?","JPN":"どう？　艦船のシグナルは届いた？","ENG":"Okay, did you find the ship's signals?","TWN":"怎麼樣？有找到艦船訊號嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"아직 먹통이야. 아무래도 우리만 조난당한 것 같아.","JPN":"まだダメ。どうやら私たちだけ遭難したみたい。","ENG":"Not yet. We might be the only ones who got stranded.","TWN":"還沒，很可能遇難的只有我們。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"이, 이상하네. 분명 다이브 할 때까지는 다른 사람들도 함께 있었는데, 침식체들이랑 싸우다 보니 어느 순간 모두 사라졌어.","JPN":"お、おかしいね。ダイブするまでは他の人たちも確かに一緒にいたのに、侵食体と戦ってる間にいなくなってたの。","ENG":"This makes no sense. All the others who dove with us disappeared while we were busy fighting C.O.s.","TWN":"奇…奇怪。明明躍入的時候，其他人都還在，但和侵蝕體交手後就突然消失不見？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"게다가 이 숲… 함선에서는 본적 없던 풍경이라고. 환경이 바뀌다니, 말이 안 되지 않아?","JPN":"それにこの森……艦船からは見たことない風景だな。環境が変わるなんてあり得ない話だ。","ENG":"Besides, this forest. I don't remember seeing it from the ship. But the environment can't have changed, can it?","TWN":"還有這片森林…我從未在艦船裡看過這種景象，環境竟然變了，不覺得很奇怪嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"애초에 이면세계잖아. 여기서 말이 되는 일만 기대하는 게 욕심일지도 모르지.","JPN":"そもそも裏世界でしょ。あり得るはずのことを期待する方が贅沢かもしれない。","ENG":"We're on the Counterside. Anything can happen here.","TWN":"我們不是在異界嗎？在異界哪有所謂的正常。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"린의 말이 맞아. 고심도에서는 충분히 일어날 수 있는 일이니까.","JPN":"リンの言うとおりね。高深度では十分に起こり得ることだから。","ENG":"Lin's right. Things like this can happen, especially in the hyperdepths.","TWN":"曉琳說的沒錯，在高深度確實有可能發生這種事。"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_NULL_NULL","text":{"KOREA":"그러니 이럴 때일수록 당황하지 말고 정신 바짝 차려야 해. 할 수 있지?","JPN":"だからこういう時こそ、慌てずに気を引き締めていこう。いいね？","ENG":"So, we'd better stay sharp. Get it?","TWN":"所以越是在這種時候，越要保持冷靜，懂吧？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"KIMSOBIN_ALT_NULL_NULL","text":{"KOREA":"으, 응! 대장만 믿을게!","JPN":"う、うん！　隊長を信じる！","ENG":"O-okay! I'm counting on you, Cap!","TWN":"嗯嗯！我相信隊長！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"KIMSOBIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"응?","JPN":"ん？","ENG":"Hm?","TWN":"嗯？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"앗, TV다! 저 나무 위에 TV가 있어!","JPN":"あっ、テレビ！　あの木の上にテレビがあるぞ！","ENG":"Ah, a TV! There's a TV on the tree over there!","TWN":"是電視！那個樹上有電視！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"뭐래? 이런 곳에 TV 같은 게 있을 리가…","JPN":"はあ？　こんな所にテレビなんかあるわけ……","ENG":"What are you talking about? What TV in a place like—","TWN":"胡說什麼！樹上怎麼可能有電視…"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>평온한 밤입니다, 여러분!</color>","JPN":"<color=#ffd34c>こんばんは、皆様！</color>","ENG":"<color=#ffd34c>It's a peaceful night, everyone.</color>","TWN":"<color=#ffd34c>哈囉～大家晚安！</color>"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"TV_NPC_NOMA_NONAME","text":{"KOREA":"<color=#ffd34c>곧 정신없는 난장판이 펼쳐지겠지만, 적어도 지금은 이 숲의 고요함을 즐기며 이야길 나눌 수 있겠군요!</color>","JPN":"<color=#ffd34c>間もなく大騒ぎになるでしょうが、少なくとも今だけはこの森の静けさを楽しみながらお話できますね！</color>","ENG":"<color=#ffd34c>Soon, that'll change, but let's try to enjoy the quietness of this forest while we can, shall we?</color>","TWN":"<color=#ffd34c>雖然很快就會掀起一片腥風血雨，但現在就好好享受這暴風雨前的寧靜吧！</color>"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"…진짜 TV잖아?","JPN":"本当にテレビがある……","ENG":"...There really is a TV.","TWN":"…真的是電視？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":null,"C":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"헤헤, 거 봐! 내 말이 맞지?","JPN":"へへ、ほら！　俺の勘違いじゃないだろ？","ENG":"Heh heh. See, I told you!","TWN":"哈哈，你看，我沒說錯吧！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"XIAOLIN_ALT_NULL_NULL","text":{"KOREA":"하지만 어떻게 이런 고심도에서 TV 같은 게 멀쩡히 작동할 수 있는 거지?","JPN":"でもどうしてこんな高深度でテレビが普通に映ってるの？","ENG":"But how is it still working in the hyperdepths?","TWN":"在這種高深度的地方，電視怎麼可能還可以正常運作呢？"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"YOOJIN_ALT_NULL_NULL","text":{"KOREA":"앗?! 그러고 보니?","JPN":"あっ！？　確かに！","ENG":"Ah, you're right!","TWN":"對欸，說的也是！"},"stage":{"bg":"COUNTERSIDE_FOREST","slots":{"L":{"char_id":"YOOJIN_ALT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"XIAOLIN_ALT_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};